const WRAP = '<svg viewBox="0 0 64 64" width="1em" height="1em" fill="none" aria-hidden="true">';
let n = 0;
const wrap = (inner: string): string => (inner ? `${WRAP}${inner.split('__ID__').join('ga' + (n++))}</svg>` : '');

/** Inline-SVG art for a perk/evolution/event glyph (tint via CSS color / the --accent var). */
export function glyphArt(key: GlyphKey): string { return wrap(ART[key]); }
export function hasGlyphArt(key: string): key is GlyphKey {
  return Object.prototype.hasOwnProperty.call(ART, key);
}

/** Inline-SVG art for a cursed-relic card. */
export function relicGlyphArt(id: RelicId): string { return wrap(RELIC_ART[id]); }

/** Inline-SVG art for a power-up (HUD badge — currentColor tints to the buff colour). */
export function powerupGlyphArt(kind: PowerupKind): string { return wrap(POWERUP_ART[kind]); }

/** Power-up art with a FIXED colour baked in (currentColor → color) for canvas rasterization
 *  (the field pickup), where currentColor can't resolve. Whites/blacks (highlights/shadows) stay. */
export function powerupGlyphColored(kind: PowerupKind, color: string): string {
  return wrap(POWERUP_ART[kind]).split('currentColor').join(color);
}
